class Solution {
    public int canBeTypedWords(String text, String brokenLetters) {
        int count = 0;
        String[] words = text.split(" ");
        String[] brokenLettersSet = brokenLetters.split("");

        for (String word : words) {
            boolean[] usedLetters = new boolean[26];
            for (char letter : word.toCharArray()) {
                usedLetters[letter - 'a'] = true;
            }

            for (char letter : brokenLettersSet) {
                if (usedLetters[letter - 'a']) {
                    usedLetters[letter - 'a'] = false;
                    count++;
                }
            }
            usedLetters[0] = false; // reset usedLetters array
        }

        return count;
    }
}
```

